# Now I see! There are different date formats AND some "unknown" values
# Let me parse dates more carefully and handle these cases

def parse_date_flexible(date_str):
    if pd.isna(date_str) or date_str == 'unknown':
        return pd.NaT
    try:
        return pd.to_datetime(date_str, format='%Y-%m-%d')
    except:
        try:
            return pd.to_datetime(date_str, format='%m/%d/%Y')
        except:
            try:
                return pd.to_datetime(date_str, format='%B %d, %Y')
            except:
                try:
                    return pd.to_datetime(date_str)
                except:
                    return pd.NaT

df['signup_date_parsed'] = df['signup_date'].apply(parse_date_flexible)

print("Successfully parsed dates:")
print(f"Total rows: {len(df)}")
print(f"Successfully parsed: {df['signup_date_parsed'].notna().sum()}")
print(f"Failed to parse: {df['signup_date_parsed'].isna().sum()}")

# Now let's look at the data again
df['signup_year'] = df['signup_date_parsed'].dt.year
df['signup_month'] = df['signup_date_parsed'].dt.month
df['signup_quarter'] = df['signup_date_parsed'].dt.quarter
df['signup_year_quarter'] = df['signup_date_parsed'].dt.year.astype(str) + '-Q' + df['signup_date_parsed'].dt.quarter.astype(str)

print("\nSignup distribution by year:")
print(df['signup_year'].value_counts().sort_index())
